-- تحديث دور المستخدم RADMAN إلى admin
UPDATE users 
SET role = 'admin' 
WHERE username = 'RADMAN';

-- التحقق من التحديث
SELECT id, username, email, role FROM users WHERE username = 'RADMAN';

-- الحصول على عدد الصلاحيات المتاحة الآن
SELECT COUNT(*) as total_permissions FROM permissions;

